@namespace Lumeo
@implements IDisposable

<div class="@CssClass" style="@HiddenStyle" role="@(AriaLabel is null ? null : "img")" aria-label="@AriaLabel" @attributes="AdditionalAttributes">
    <CascadingValue Value="_imageContext" IsFixed="false">
        <div class="@InnerClasses">
            @ChildContent
        </div>
    </CascadingValue>
    @if (Status != AvatarStatus.None)
    {
        @* The status is conveyed by colour; role=img + aria-label give it a text
           alternative so it isn't colour-only (WCAG 1.4.1). *@
        <span class="absolute bottom-0 right-0 block h-2.5 w-2.5 rounded-full ring-2 ring-background @StatusColor"
              role="img" aria-label="@EffectiveStatusLabel"></span>
    }
</div>

@code {
    [CascadingParameter] private AvatarGroup.AvatarGroupContext? GroupContext { get; set; }

    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>Avatar size. Supported values: <see cref="Lumeo.Size.Sm"/>,
    /// <see cref="Lumeo.Size.Md"/> (default), <see cref="Lumeo.Size.Lg"/>,
    /// <see cref="Lumeo.Size.Xl"/>. Other values fall through to <c>Md</c>.</summary>
    [Parameter] public Lumeo.Size Size { get; set; } = Lumeo.Size.Md;
    [Parameter] public AvatarShape Shape { get; set; } = AvatarShape.Circle;
    [Parameter] public AvatarStatus Status { get; set; } = AvatarStatus.None;
    /// <summary>Accessible label for the status dot (e.g. "Online"). Defaults to the
    /// <see cref="AvatarStatus"/> name; override to localize. Exposed as the dot's
    /// <c>aria-label</c> so the status isn't conveyed by colour alone (WCAG 1.4.1).</summary>
    [Parameter] public string? StatusLabel { get; set; }
    /// <summary>Accessible name announced for the avatar. When set, the
    /// component renders <c>role="img"</c> + <c>aria-label</c> so a
    /// screen-reader has something to read. Useful for image-only avatars
    /// (no initials in <see cref="ChildContent"/>) where the user's name
    /// is the meaningful AT context.</summary>
    [Parameter] public string? AriaLabel { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Image→fallback coordination. AvatarImage reports load success/failure;
    // AvatarFallback subscribes and only paints itself while the image hasn't
    // successfully loaded (mirrors Radix's <Avatar.Image>/<Avatar.Fallback>).
    private readonly AvatarImageContext _imageContext = new();

    // Group capping: an Avatar inside an AvatarGroup with Max set registers for
    // an ordinal slot. Slots beyond Max are visually hidden so the group can
    // render a single "+N" overflow chip in their place.
    private readonly object _groupToken = new();
    private bool _hiddenByGroup;

    protected override void OnInitialized()
    {
        GroupContext?.Register(_groupToken);
    }

    protected override void OnParametersSet()
    {
        // Recompute visibility against the group each render — the group's Max
        // or member set can change after our initial registration.
        _hiddenByGroup = GroupContext?.IsHidden(_groupToken) ?? false;
    }

    public void Dispose() => GroupContext?.Unregister(_groupToken);

    // Hidden group members keep their layout slot collapsed; using display:none
    // (rather than not rendering) keeps the cascading image context stable.
    private string? HiddenStyle => _hiddenByGroup ? "display: none;" : null;

    // Outer wrapper inherits ShapeClasses too so consumer-supplied borders / rings
    // (e.g. border-2 border-background in an AvatarGroup) follow the avatar's
    // shape. Without this, the border landed on the rectangular outer div while
    // the inner div clipped the image to a circle — visible as square frames
    // around fallback initials.
    private string CssClass => Cx.Merge("relative flex shrink-0", SizeClasses, ShapeClasses, Class);

    private string InnerClasses => $"flex h-full w-full overflow-hidden {ShapeClasses}";

    private string ShapeClasses => Shape switch
    {
        AvatarShape.Square => "rounded-md",
        _ => "rounded-full"
    };

    private string SizeClasses => Size switch
    {
        Lumeo.Size.Xxs => "h-5 w-5 text-[10px]",
        Lumeo.Size.Sm => "h-8 w-8",
        Lumeo.Size.Lg => "h-12 w-12",
        Lumeo.Size.Xl => "h-16 w-16",
        _ => "h-10 w-10"
    };

    private string StatusColor => Status switch
    {
        AvatarStatus.Online => "bg-success",
        AvatarStatus.Offline => "bg-muted-foreground",
        AvatarStatus.Away => "bg-warning",
        AvatarStatus.Busy => "bg-destructive",
        _ => ""
    };

    // Text alternative for the status dot — the consumer override, else the enum name.
    private string EffectiveStatusLabel => StatusLabel ?? Status.ToString();

    public enum AvatarShape { Circle, Square }
    public enum AvatarStatus { None, Online, Offline, Away, Busy }

    /// <summary>
    /// Shared mutable state for the image→fallback chain. <see cref="AvatarImage"/>
    /// flips <see cref="ImageLoaded"/> false on <c>onerror</c> (or when its
    /// <c>Src</c> is blank); <see cref="AvatarFallback"/> renders only while the
    /// image is NOT loaded. State changes fan out to subscribers via
    /// <see cref="OnChange"/> so both children re-render together.
    /// </summary>
    public sealed class AvatarImageContext
    {
        public bool ImageLoaded { get; private set; }
        public event Action? OnChange;

        public void SetLoaded(bool loaded)
        {
            if (ImageLoaded == loaded) return;
            ImageLoaded = loaded;
            OnChange?.Invoke();
        }
    }
}

@namespace Lumeo
@implements IDisposable

@* Renders only while the sibling AvatarImage has NOT successfully loaded — the
   Radix image→fallback chain. Used standalone (no Avatar parent) it always
   renders, so existing fallback-only usages are unaffected. *@
@if (ShowFallback)
{
    <div class="@CssClass" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
}

@code {
    [CascadingParameter] private Avatar.AvatarImageContext? ImageContext { get; set; }

    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private Avatar.AvatarImageContext? _subscribed;

    private bool ShowFallback => ImageContext is null || !ImageContext.ImageLoaded;

    protected override void OnParametersSet()
    {
        // (Re)subscribe to the active context so an image that loads/errors
        // after first paint flips our visibility without the parent forcing it.
        if (!ReferenceEquals(_subscribed, ImageContext))
        {
            if (_subscribed is not null) _subscribed.OnChange -= OnImageStateChanged;
            _subscribed = ImageContext;
            if (_subscribed is not null) _subscribed.OnChange += OnImageStateChanged;
        }
    }

    private void OnImageStateChanged() => InvokeAsync(StateHasChanged);

    private string CssClass => Cx.Merge("flex h-full w-full items-center justify-center rounded-full bg-muted text-sm font-medium", Class);

    public void Dispose()
    {
        if (_subscribed is not null) _subscribed.OnChange -= OnImageStateChanged;
    }
}

@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">
    @* The cascaded context is recreated each render carrying the live member
       count + Max, so a non-fixed CascadingValue propagates to child Avatars
       and they re-evaluate IsHidden when membership settles. The stable
       registrar inside it keeps ordering across those re-renders. *@
    <CascadingValue Value="CurrentContext" IsFixed="false">
        @ChildContent
    </CascadingValue>
    @if (OverflowCount > 0)
    {
        <div class="@OverflowClasses">
            <span class="text-xs font-medium">+@OverflowCount</span>
        </div>
    }
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Maximum number of avatars to show before collapsing the rest
    /// into a single "+N" overflow chip. <c>0</c> (default) shows them all.</summary>
    [Parameter] public int Max { get; set; }

    /// <summary>
    /// Optional explicit total used to compute "+N". Set this when the group
    /// represents more people than the avatars actually rendered (e.g. "show 3
    /// of 50"): the chip then reads <c>Total - Max</c>. When left at <c>0</c>
    /// the overflow is computed from the number of child avatars instead, so a
    /// plain group of N children with <c>Max</c> set "just works".
    /// </summary>
    [Parameter] public int Total { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly AvatarGroupRegistrar _registrar;
    private int _lastRenderedCount = -1;

    public AvatarGroup()
    {
        _registrar = new AvatarGroupRegistrar(OnMembersChanged);
    }

    // New context instance per render → non-fixed CascadingValue notifies
    // children, so they recompute visibility once all siblings have registered.
    private AvatarGroupContext CurrentContext => new(_registrar, Max);

    private void OnMembersChanged()
    {
        // Re-render once the membership count settles so hidden slots + the
        // overflow chip reflect the final set. Guard on the count to avoid a
        // render loop (register fires during our own ChildContent render).
        if (_registrar.Count != _lastRenderedCount)
        {
            InvokeAsync(StateHasChanged);
        }
    }

    protected override void OnAfterRender(bool firstRender)
    {
        _lastRenderedCount = _registrar.Count;
    }

    // Effective total: explicit Total wins; otherwise the live child count.
    private int EffectiveTotal => Total > 0 ? Total : _registrar.Count;

    private int OverflowCount => Max > 0 && EffectiveTotal > Max ? EffectiveTotal - Max : 0;

    private string CssClass => Cx.Merge("flex -space-x-3", Class);
    private const string OverflowClasses = "relative flex h-10 w-10 shrink-0 items-center justify-center rounded-full border-2 border-background bg-muted text-muted-foreground";

    /// <summary>
    /// Stable registry of the group's member avatars, preserving DOM order
    /// across re-renders. Avatars register a token in their OnInitialized.
    /// </summary>
    public sealed class AvatarGroupRegistrar
    {
        private readonly List<object> _members = new();
        private readonly Action _onChange;

        public AvatarGroupRegistrar(Action onChange) => _onChange = onChange;

        public int Count => _members.Count;

        public void Register(object token)
        {
            if (_members.Contains(token)) return;
            _members.Add(token);
            _onChange();
        }

        public void Unregister(object token)
        {
            if (_members.Remove(token)) _onChange();
        }

        public int IndexOf(object token) => _members.IndexOf(token);
    }

    /// <summary>
    /// Cascaded to child <see cref="Avatar"/>s so the group can cap how many are
    /// visible. Tokens at an ordinal index &gt;= <c>Max</c> report
    /// <see cref="IsHidden"/> true and collapse, leaving room for the "+N" chip.
    /// </summary>
    public sealed record AvatarGroupContext(AvatarGroupRegistrar Registrar, int Max)
    {
        public void Register(object token) => Registrar.Register(token);
        public void Unregister(object token) => Registrar.Unregister(token);

        public bool IsHidden(object token)
        {
            if (Max <= 0) return false;
            var index = Registrar.IndexOf(token);
            return index >= 0 && index >= Max;
        }
    }
}

@namespace Lumeo

@* The image hides itself once it has errored (or when Src is blank) so the
   sibling AvatarFallback can take over — the Radix image→fallback chain.
   Rendering is suppressed rather than just visually hidden so a broken-image
   glyph never flashes. When used standalone (no Avatar parent) there's no
   context and the image always renders, preserving the old behaviour. *@
@if (ShowImage)
{
    <img class="@CssClass" src="@Src" alt="@Alt" @attributes="AdditionalAttributes"
         @onload="HandleLoad" @onerror="HandleError" />
}

@code {
    [CascadingParameter] private Avatar.AvatarImageContext? ImageContext { get; set; }

    [Parameter] public string? Src { get; set; }
    [Parameter] public string? Alt { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter] public EventCallback OnError { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _errored;

    private string CssClass => Cx.Merge("aspect-square h-full w-full object-cover", Class);

    // Render unless we've errored. A blank Src counts as an immediate error so
    // the fallback shows without waiting for the browser to fire onerror.
    private bool ShowImage => !_errored;

    protected override void OnParametersSet()
    {
        if (string.IsNullOrEmpty(Src))
        {
            _errored = true;
            ImageContext?.SetLoaded(false);
        }
        else if (_errored)
        {
            // Src changed to a real value after a previous failure — give it
            // another chance to load.
            _errored = false;
        }
    }

    private void HandleLoad()
    {
        _errored = false;
        ImageContext?.SetLoaded(true);
    }

    private async Task HandleError()
    {
        _errored = true;
        ImageContext?.SetLoaded(false);
        await OnError.InvokeAsync();
    }
}
